1	// Agent-bridge routes (Task 16.5 handoff/review, 16.8 plan-off — server half).
2	// Every agent-spawning + transcript + git action is an INJECTED seam so this file has no
3	// provider/store knowledge and tests stay hermetic. The daemon lead binds `startSession`
4	// to term.ts's session-start machinery (agreed signature below).
5	
6	import { randomBytes } from 'node:crypto';
7	import { mkdir, readFile, rename, stat, writeFile } from 'node:fs/promises';
8	import { join } from 'node:path';
9	import type { FastifyInstance } from 'fastify';
10	import { composeBrief as realBrief, composeDiffReview as realReview } from '../lib/bridge/brief';
11	import {
12	  pickWinner,
13	  runPlanoff as realPlanoff,
14	  winnerMarkdown,
15	  type PlanoffProvider,
16	  type PlanoffResult,
17	} from '../lib/bridge/planoff';
18	import { decodeProjectDir } from '../lib/store/scan';
19	import { getProviders, type ProviderId } from '../lib/providers/types';
20	import { bridgeStatus as realBridgeStatus, registerBridge as realRegister } from '../lib/bridge/registry';
21	import { peekTerminal as realPeekTerminal } from '../lib/bridge/peek';
22	import { dial as realDial } from '../daemon-client';
23	import type { NIStatus } from '../lib/needs-input';
24	
25	// Agreed with the daemon lead: bridge spawns a fresh opposite-provider (or winner) session,
26	// seeded with a first prompt. tabMeta carries the linked/pair metadata for the UI.
27	export interface StartSessionOpts {
28	  projectPath: string;
29	  provider: ProviderId;
30	  firstPrompt: string;
31	  linkSrc?: { sessionId: string; kind: 'handoff' | 'review' };
32	}
33	export type StartSession = (opts: StartSessionOpts) => Promise<{ ptyId: string; tabMeta: unknown }>;
34	
35	export interface BridgeRouteDeps {
36	  startSession: StartSession;
37	  // default: look the project up in the providers' stores (real cwd); decode
38	  // is only the last-ditch fallback — it mangles hyphenated repo names.
39	  resolveRepo?: (projectId: string) => string | null | Promise<string | null>;
40	  resolveSessionProvider?: (projectId: string, sessionId: string) => Promise<ProviderId>;
41	  resolveLatestSession?: (projectId: string) => Promise<string | null>; // 'latest' sentinel
42	
43	  composeBrief?: (projectId: string, sessionId: string) => Promise<string>;
44	  composeDiffReview?: (projectId: string, sessionId: string) => Promise<string>;
45	  runPlanoff?: (projectPath: string, task: string) => Promise<PlanoffResult>;
46	  now?: () => number; // clock for scratchpad entry timestamps (injectable for tests)
47	  // MCP bridge registration (explicit Register button). Default writes the real agent
48	  // configs; injectable for tests so no real ~/.claude.json / ~/.codex/config.toml is touched.
49	  registerBridge?: () => Promise<void>;
50	  bridgeStatus?: () => Promise<{ claude: boolean; codex: boolean }>;
51	
52	  // Spec 5: wait_for_status / read_terminal. Both need to resolve a project+session
53	  // down to a LIVE ptyId (cwd match against the daemon's list()) before acting.
54	  // listLivePtys is injected so tests fake the daemon instead of dialing a real one.
55	  listLivePtys?: () => Promise<{ ptyId: string; cwd: string }[]>;
56	  waitForStatus?: (ptyId: string, status: NIStatus, timeoutSec?: number) => Promise<{ status: NIStatus | 'timeout' }>;
57	  peekTerminal?: (ptyId: string, lines?: number) => Promise<{ ptyId: string; lines: string[] }>;
58	}
59	
60	const OTHER: Record<ProviderId, ProviderId> = { claude: 'codex', codex: 'claude' };
61	
62	function providerName(p: ProviderId): string {
63	  return p === 'codex' ? 'Codex' : 'Claude';
64	}
65	
66	async function isDir(path: string): Promise<boolean> {
67	  try {
68	    return (await stat(path)).isDirectory();
69	  } catch {
70	    return false;
71	  }
72	}
73	
74	async function atomicWrite(path: string, content: string): Promise<void> {
75	  const dir = join(path, '..');
76	  await mkdir(dir, { recursive: true });
77	  const tmp = join(dir, `.${randomBytes(6).toString('hex')}.tmp`);
78	  await writeFile(tmp, content, 'utf8');
79	  await rename(tmp, path);
80	}
81	
82	async function appendScratchpad(repo: string, text: string): Promise<void> {
83	  const path = join(repo, '.seshmux', 'handoff.md');
84	  let existing = '';
85	  try {
86	    existing = await readFile(path, 'utf8');
87	  } catch {
88	    /* first write */
89	  }
90	  await atomicWrite(path, existing + (existing && !existing.endsWith('\n') ? '\n' : '') + text + '\n');
91	}
92	
93	// Default: resolve the source session's provider via the providers registry.
94	async function defaultResolveProvider(projectId: string, sessionId: string): Promise<ProviderId> {
95	  const providers = await getProviders();
96	  for (const p of providers) {
97	    const sessions = await p.listSessions(projectId).catch(() => []);
98	    if (sessions.some((s) => s.id === sessionId)) return p.id;
99	  }
100	  return 'claude'; // fallback
101	}
102	
103	// Resolve the project's most-recently-touched session. Lets a live terminal tab
104	// that doesn't know its own sessionId (rehydrated PTY, fresh spawn) bridge from
105	// "whatever this project was just doing" — the live session keeps appending to
106	// its jsonl, so newest-mtime is it in the common case.
107	// ponytail: ambiguous with two concurrent live sessions in one repo; good enough
108	// until a real ptyId→sessionId feed exists in the events hub.
109	async function defaultResolveLatest(projectId: string): Promise<string | null> {
110	  const providers = await getProviders();
111	  let best: { id: string; mtime: number } | null = null;
112	  for (const p of providers) {
113	    const sessions = await p.listSessions(projectId).catch(() => []);
114	    for (const s of sessions) {
115	      if (!best || s.mtime > best.mtime) best = { id: s.id, mtime: s.mtime };
116	    }
117	  }
118	  return best?.id ?? null;
119	}
120	
121	// Default repo resolver: providers know each project's REAL cwd (read from the
122	// session files) — `decodeProjectDir` alone turns every "-" into "/", so
123	// hyphenated repos (wp-sleepfoundation-org) decode to paths that don't exist.
124	// Module-level (not a route-function closure) so index.ts's Spec 5 wait-socket
125	// wiring can reuse the SAME resolution logic instead of a second copy.
126	export async function defaultResolveRepo(id: string): Promise<string | null> {
127	  const providers = await getProviders();
128	  for (const p of providers) {
129	    const projects = await p.scanProjects().catch(() => []);
130	    const hit = projects.find((pr) => pr.id === id);
131	    if (hit) return hit.path;
132	  }
133	  return decodeProjectDir(id).path;
134	}
135	
136	// Default live-ptys source for Spec 5 wait/peek target resolution — same
137	// dial+list()+cwd pattern as GET /api/sessions/live in term.ts. Exported for
138	// index.ts's wait-socket wiring (same reuse rationale as defaultResolveRepo).
