1	// MCP bridge server (Task 16.7): exposes ask_codex / ask_claude tools that run the OTHER
2	// agent headless in the caller's cwd, with hop-budget + no-loop + approval guardrails.
3	//
4	// BEHAVIOR DISCOVERY (real runs on this machine, 2026-07-08 — verify before trusting):
5	//   claude CLI 2.1.205 · codex-cli 0.143.0
6	//
7	//   claude -p "<q>"                      → auth inherited (no login prompt); stdout = plain
8	//     answer text; exit 0; ~6s for a tiny prompt. git working tree untouched by a read prompt.
9	//   claude -p --output-format json "<q>" → single JSON object; `.result` = answer text,
10	//     `.is_error` bool, `.total_cost_usd`, `.session_id`, `.permission_denials[]`. exit 0.
11	//   claude -p --permission-mode plan "<write request>" → PROVABLY READ-ONLY: it plans but
12	//     does NOT write (verified: requested file never created, git clean). Writes a plan file
13	//     into ~/.claude/plans/ (outside the repo). Used by plan-off (16.8).
14	//
15	//   codex exec -s read-only -C <dir> "<q>"  → auth inherited; `-s read-only` sandbox; `-C`
16	//     sets working root. Plain stdout ends with the answer line. exit 0. IMPORTANT: codex
17	//     reads stdin ("Reading additional input from stdin...") — MUST redirect stdin from
18	//     /dev/null or it hangs waiting for input.
19	//   codex exec ... --json "<q>"          → NDJSON event stream: thread.started, turn.started,
20	//     item.completed (item.type==='agent_message' carries `.text` = the answer), turn.completed
21	//     (has `.usage`). exit 0.
22	//   codex read-only asked to WRITE       → refuses ("filesystem is read-only"), git clean, exit 0.
23	//
24	// So: both agents run headless with inherited auth and exit 0 on success. For ask_* we want a
25	// plain answer, so use `claude -p <q>` and `codex exec -s read-only -C <cwd> <q> </dev/null`.
26	// A permission-requiring tool call in read-only mode is refused, not hung — safe default.
27	
28	import { execFile } from 'node:child_process';
29	import { randomBytes } from 'node:crypto';
30	import { mkdir, appendFile } from 'node:fs/promises';
31	import { homedir } from 'node:os';
32	import { join } from 'node:path';
33	import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
34	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
35	import { z } from 'zod';
36	import { requestApprovalOverSocket } from './approval-socket';
37	
38	export const HOP_ENV = 'SESHMUX_HOP';
39	
40	export type BridgeTarget = 'claude' | 'codex';
41	
42	export class BridgeLoopError extends Error {
43	  constructor(hop: number, budget: number) {
44	    super(`bridge hop budget exceeded: incoming hop ${hop} >= budget ${budget}`);
45	    this.name = 'BridgeLoopError';
46	  }
47	}
48	
49	export interface RunAgentArgs {
50	  bin: BridgeTarget;
51	  prompt: string;
52	  cwd: string;
53	  hop: number;
54	}
55	
56	export interface BridgeLogEntry {
57	  ts: number;
58	  target: BridgeTarget;
59	  question: string;
60	  answer: string;
61	  hop: number;
62	  ok: boolean;
63	}
64	
65	// Spec 5: wait_for_status/read_terminal go through the SAME approval gate as
66	// ask_* but don't spawn a specific agent bin — ApprovalTarget widens beyond
67	// BridgeTarget to cover them (approval-socket.ts's `tool` union already does).
68	export type ApprovalTarget = BridgeTarget | 'wait_for_status' | 'read_terminal';
69	
70	export interface BridgeDeps {
71	  runAgent: (args: RunAgentArgs) => Promise<{ text: string; ok: boolean }>;
72	  requestApproval: (info: { target: ApprovalTarget; question: string; cwd: string; hop: number }) => Promise<boolean>;
73	  log: (entry: BridgeLogEntry) => Promise<void>;
74	  budget: number; // hop budget (default 10 at call sites)
75	  approvalMode?: boolean; // default true — gate every call on UI approval
76	  now?: () => number; // injectable clock (tests avoid Date.now)
77	  // Spec 5: wait_for_status crosses into the WEB SERVER process (the events-hub
78	  // lives there, this mcp-bridge process doesn't) via the wait-socket transport.
79	  waitForStatus?: (req: { project: string; session?: string; status: string; timeoutSec?: number }) => Promise<{ status: string; error?: string }>;
80	  // Spec 5: read_terminal is self-contained — resolves a live ptyId itself
81	  // (dial the daemon directly, no server process needed) then peeks scrollback.
82	  // cwd is returned alongside ptyId so the caller can refuse reading its OWN
83	  // session (cwd === process.cwd()).
84	  resolveLivePty?: (project: string) => Promise<{ ptyId: string; cwd: string } | null>;
85	  peekTerminal?: (ptyId: string, lines?: number) => Promise<{ ptyId: string; lines: string[] }>;
86	}
87	
88	export interface BridgeCall {
89	  target: BridgeTarget;
90	  question: string;
91	  cwd: string;
92	  hopEnv: string | undefined; // incoming SESHMUX_HOP value
93	}
94	
95	// Incoming hop → this call's hop number. Unset/invalid → 1 (first hop).
96	export function nextHop(hopEnv: string | undefined): number {
97	  const n = Number(hopEnv);
98	  return Number.isFinite(n) && n >= 0 ? n + 1 : 1;
99	}
100	
101	// Hop-tagged prompt so the far side knows its depth and can refuse to recurse further.
102	function tagPrompt(question: string, hop: number): string {
103	  return `[seshmux-bridge hop=${hop}] ${question}`;
104	}
105	
106	// Shared preamble for EVERY bridge verb (ask_*, wait_for_status, read_terminal):
107	// loop guard → approval. Factored out of runBridgedCall so wait/peek (which don't
108	// spawn an agent) gate identically to ask_* without duplicating the guard logic.
109	// Throws BridgeLoopError / a denial Error — callers decide how to surface that
110	// (ask_* lets it propagate as an MCP isError result; wait/peek do the same).
111	export async function guardBridgeCall(
112	  call: { target: ApprovalTarget; question: string; cwd: string; hopEnv: string | undefined },
113	  deps: Pick<BridgeDeps, 'requestApproval' | 'budget' | 'approvalMode'>,
114	): Promise<{ hop: number }> {
115	  const hop = nextHop(call.hopEnv);
116	
117	  // No-loop rule: refuse once the incoming depth reaches the budget (before any spawn).
118	  const incoming = Number(call.hopEnv);
119	  if (Number.isFinite(incoming) && incoming >= deps.budget) {
120	    throw new BridgeLoopError(incoming, deps.budget);
121	  }
122	
123	  // Approval gate (default ON): block until approved. The default requestApproval blocks on
124	  // the UI over the approval socket, with a server-side 120s timeout → deny (fail-closed).
125	  if (deps.approvalMode !== false) {
126	    const approved = await deps.requestApproval({
127	      target: call.target,
128	      question: call.question,
129	      cwd: call.cwd,
130	      hop,
131	    });
132	    if (!approved) throw new Error('bridge call denied (approval not granted)');
133	  }
134	
135	  return { hop };
136	}
137	
138	// The guarded core: loop guard → approval → run → log. Deps injected for testing.
139	export async function runBridgedCall(call: BridgeCall, deps: BridgeDeps): Promise<{ text: string }> {
140	  const { hop } = await guardBridgeCall(call, deps);
141	
142	  const result = await deps.runAgent({
143	    bin: call.target,
144	    prompt: tagPrompt(call.question, hop),
145	    cwd: call.cwd,
146	    hop,
147	  });
148	
149	  const now = deps.now ? deps.now() : 0;
150	  await deps.log({
151	    ts: now,
152	    target: call.target,
153	    question: call.question,
154	    answer: result.text,
155	    hop,
156	    ok: result.ok,
157	  });
158	
159	  return { text: result.text };
160	}
161	
162	// Default real runner using the verified headless invocations. hop is threaded via the
163	// SESHMUX_HOP env so a bridged agent that calls back knows its depth.
164	export async function defaultRunAgent(args: RunAgentArgs): Promise<{ text: string; ok: boolean }> {
165	  // SECURITY: prompt + cwd become argv. A leading `-` could parse as a CLI flag (argument
166	  // injection) — e.g. `--dangerously-skip-permissions` would defeat the codex read-only
167	  // sandbox. Reject leading-`-` here (defense-in-depth atop the provider's `--` shield).
168	  // Prompts are hop-tagged (`[seshmux-bridge hop=N] …`) so never legitimately start with `-`.
169	  if (/^-/.test(args.prompt)) return { text: 'bridge prompt may not start with "-"', ok: false };
170	  if (/^-/.test(args.cwd)) return { text: 'bridge cwd may not start with "-"', ok: false };
171	
172	  // Binary name + sandbox flags come from the PROVIDER (hard rule 3) — this file only spawns.
173	  const { getProviders } = await import('../providers/types');
174	  const providers = await getProviders();
175	  const provider = providers.find((p) => p.id === args.bin);
176	  if (!provider) return { text: `unknown provider: ${args.bin}`, ok: false };
177	  const [bin, ...rest] = provider.commands.headlessAsk(args.cwd, args.prompt);
178	
179	  const env = { ...process.env, [HOP_ENV]: String(args.hop) };
180	  return new Promise((resolve) => {
181	    const child = execFile(
182	      bin,
183	      rest,
184	      { cwd: args.cwd, env, timeout: 120_000, maxBuffer: 16 * 1024 * 1024 },
185	      (err, stdout) => resolve({ text: (stdout || '').trim(), ok: !err }),
186	    );
187	    child.stdin?.end(); // codex reads stdin; harmless no-op for claude
188	  });
189	}
190	
191	// ---------------------------------------------------------------------------
192	// Task 16.7: MCP stdio server exposing ask_codex / ask_claude to whichever
193	// agent has this bridge registered as an MCP tool provider.
194	// ---------------------------------------------------------------------------
195	
196	// Default logger: append one JSON line per exchange to <configDir>/bridge-log.jsonl.
197	// Uses bridgeConfigDir() so it honors SESHMUX_CONFIG_DIR — same dir as approval.sock, so a
198	// custom config dir keeps the log next to the socket instead of a stale ~/.config/seshmux.
199	// Never throws — a logging failure must not break a bridge call.
200	export async function defaultBridgeLog(entry: BridgeLogEntry): Promise<void> {
201	  try {
202	    const dir = bridgeConfigDir();
203	    await mkdir(dir, { recursive: true });
204	    await appendFile(join(dir, 'bridge-log.jsonl'), JSON.stringify(entry) + '\n', 'utf8');
205	  } catch {
206	    /* logging must never crash the bridge */
207	  }
208	}
209	
210	// Config dir shared with the web server + daemon (env override → same as daemon/ensure.js).
211	export function bridgeConfigDir(): string {
212	  return process.env.SESHMUX_CONFIG_DIR || join(homedir(), '.config', 'seshmux');
213	}
214	function approvalSocketPath(): string {
215	  return join(bridgeConfigDir(), 'approval.sock');
216	}
217	
218	// Real approval: block on the seshmux UI over the approval socket. The web server owns the
219	// listener (it broadcasts a toast + awaits the human, with a 120s server-side timeout → deny).
220	// FAIL-CLOSED: if the server isn't listening or dies mid-approval, the client denies.
221	// `tool` names the agent that WOULD run for ask_* (target); for wait_for_status/
222	// read_terminal (Spec 5) target IS the tool name — no agent bin to name.
223	export async function defaultRequestApproval(info: {
224	  target: ApprovalTarget;
225	  question: string;
226	  cwd: string;
227	  hop: number;
228	}): Promise<boolean> {
229	  const requestId = randomBytes(12).toString('hex');
230	  const tool =
231	    info.target === 'wait_for_status' || info.target === 'read_terminal'
232	      ? info.target
233	      : info.target === 'codex'
234	        ? 'ask_codex'
235	        : 'ask_claude';
236	  return requestApprovalOverSocket(approvalSocketPath(), {
237	    requestId,
238	    tool,
239	    question: info.question,
240	    cwd: info.cwd,
241	    hop: info.hop,
242	  });
243	}
244	
245	function waitSocketPath(): string {
246	  return join(bridgeConfigDir(), 'wait.sock');
247	}
248	
249	// Real wait_for_status: hop to the WEB SERVER process over the wait socket (the
250	// events-hub this needs lives there — see wait-socket.ts doc comment). FAIL-SAFE:
251	// requestWaitOverSocket already resolves {status:'timeout'} on any transport error.
252	export async function defaultWaitForStatus(req: {
253	  project: string;
254	  session?: string;
255	  status: string;
256	  timeoutSec?: number;
257	}): Promise<{ status: string; error?: string }> {
258	  const { requestWaitOverSocket } = await import('./wait-socket');
259	  return requestWaitOverSocket(waitSocketPath(), req as Parameters<typeof requestWaitOverSocket>[1]);
260	}
261	
262	// Real read_terminal target resolution: self-contained, no server process needed
263	// (see peek.ts doc comment) — dial the daemon directly for the live ptyId list,
264	// resolve the project id to a repo path via the SAME provider registry
265	// defaultRunAgent already uses, and cwd-match. Returns cwd alongside ptyId so
266	// the caller can refuse reading its OWN session.
267	export async function defaultResolveLivePty(project: string): Promise<{ ptyId: string; cwd: string } | null> {
268	  const { getProviders } = await import('../providers/types');
269	  const { dial } = await import('../../daemon-client');
270	  const providers = await getProviders();
271	  let repo: string | null = null;
272	  for (const p of providers) {
273	    const projects = await p.scanProjects().catch(() => []);
274	    const hit = projects.find((pr) => pr.id === project);
275	    if (hit) {
276	      repo = hit.path;
277	      break;
278	    }
279	  }
280	  if (!repo) return null;
281	  let conn = null as Awaited<ReturnType<typeof dial>> | null;
282	  try {
283	    conn = await dial();
284	    const { ptys } = await conn.list();
285	    const hit = ptys.find((p) => p.alive && p.cwd === repo);
286	    return hit ? { ptyId: hit.ptyId, cwd: hit.cwd } : null;
287	  } catch {
288	    return null;
289	  } finally {
290	    if (conn) conn.close();
291	  }
292	}
293	
294	function defaultBridgeDeps(): BridgeDeps {
295	  return {
296	    runAgent: defaultRunAgent,
297	    budget: Number(process.env.SESHMUX_HOP_BUDGET) || 10,
298	    approvalMode: true,
299	    log: defaultBridgeLog,
300	    requestApproval: defaultRequestApproval,
301	    waitForStatus: defaultWaitForStatus,
302	    resolveLivePty: defaultResolveLivePty,
303	    peekTerminal: async (ptyId: string, lines?: number) => {
304	      const { peekTerminal } = await import('./peek');
305	      return peekTerminal(ptyId, lines);
306	    },
307	  };
308	}
309	
310	// Builds a BridgeCall and runs it, returning an MCP tool result. Guardrail failures
311	// (loop budget, denial) become isError results rather than thrown exceptions, so a
312	// single bad call never crashes the stdio server.
313	async function handleAsk(
314	  target: BridgeTarget,
315	  question: string,
316	  context: string | undefined,
317	  deps: BridgeDeps,
318	) {
319	  const call: BridgeCall = {
320	    target,
321	    question: question + (context ? '\n\nContext: ' + context : ''),
322	    cwd: process.cwd(),
323	    hopEnv: process.env[HOP_ENV],
324	  };
325	  try {
326	    const result = await runBridgedCall(call, deps);
327	    return { content: [{ type: 'text' as const, text: result.text }] };
328	  } catch (err) {
329	    const message = err instanceof Error ? err.message : String(err);
330	    return { content: [{ type: 'text' as const, text: message }], isError: true };
331	  }
332	}
333	
334	// Spec 5 wait_for_status tool handler: loop guard + approval (guardBridgeCall,
335	// same as ask_*), then a status wait routed to the WEB SERVER process over the
336	// wait socket (waitForStatus dep — see defaultWaitForStatus doc comment).
337	//
338	// "Never throws" is scoped to the STATUS WAIT ITSELF timing out (Spec 5 design:
339	// "resolves {status:'timeout'}, never throws — agents handle it as data") — that
340	// is a returned isError result either way, never a JS throw out of this handler.
341	// A loop-guard trip or an approval denial is a DIFFERENT condition (the wait
342	// never even started) and must stay observably distinct from a real timeout —
343	// masking it as {status:'timeout'} would make a tripped guard indistinguishable
344	// from "the target just never got there," which is exactly the bug read_terminal
345	// avoids by returning isError. Mirror that here.
346	export async function handleWait(
347	  project: string,
348	  status: string,
349	  session: string | undefined,
350	  timeoutSec: number | undefined,
351	  deps: BridgeDeps,
352	) {
353	  const cwd = process.cwd();
354	  try {
355	    await guardBridgeCall(
356	      { target: 'wait_for_status', question: `wait for ${project} to reach ${status}`, cwd, hopEnv: process.env[HOP_ENV] },
357	      deps,
358	    );
359	  } catch (err) {
360	    const message = err instanceof Error ? err.message : String(err);
361	    return { content: [{ type: 'text' as const, text: message }], isError: true };
362	  }
363	  const waitForStatus = deps.waitForStatus ?? defaultWaitForStatus;
364	  const result = await waitForStatus({ project, session, status, timeoutSec });
365	  return { content: [{ type: 'text' as const, text: JSON.stringify(result) }] };
366	}
367	
368	// Spec 5 read_terminal tool handler: refuses the caller's OWN session (its live
369	// PTY's cwd === process.cwd() — the only signal available without a real
370	// ptyId->sessionId map, same ambiguity ceiling as bridge.ts's
371	// resolvePtyForSession), then loop guard + approval, then a self-contained
372	// scrollback peek (no server process hop — see peek.ts doc comment).
373	export async function handleReadTerminal(
374	  project: string,
375	  lines: number | undefined,
376	  deps: BridgeDeps,
377	) {
378	  const cwd = process.cwd();
379	  const resolveLivePty = deps.resolveLivePty ?? defaultResolveLivePty;
380	  const target = await resolveLivePty(project);
381	  if (!target) {
382	    return { content: [{ type: 'text' as const, text: 'no live session found for this project' }], isError: true };
383	  }
384	  if (target.cwd === cwd) {
385	    return { content: [{ type: 'text' as const, text: 'read_terminal refuses to peek the caller\'s own session' }], isError: true };
386	  }
387	  try {
388	    await guardBridgeCall(
389	      { target: 'read_terminal', question: `read terminal output for ${project}`, cwd, hopEnv: process.env[HOP_ENV] },
390	      deps,
391	    );
392	  } catch (err) {
393	    const message = err instanceof Error ? err.message : String(err);
394	    return { content: [{ type: 'text' as const, text: message }], isError: true };
395	  }
396	  const peekTerminal = deps.peekTerminal ?? (async (id: string, l?: number) => (await import('./peek')).peekTerminal(id, l));
397	  const result = await peekTerminal(target.ptyId, lines);
398	  return { content: [{ type: 'text' as const, text: result.lines.join('\n') }] };
399	}
400	
401	// Creates (but does not connect) the MCP server exposing ask_codex/ask_claude.
402	// Split out from startMcpBridge so tests can register tools without opening stdio.
403	export function createMcpBridgeServer(deps: BridgeDeps = defaultBridgeDeps()): McpServer {
404	  const server = new McpServer({ name: 'seshmux-bridge', version: '1.0.0' });
405	
406	  server.registerTool(
407	    'ask_codex',
408	    {
409	      description: "Ask the Codex agent a question, running it headless in the caller's cwd.",
410	      inputSchema: {
411	        question: z.string(),
412	        context: z.string().optional(),
413	      },
414	    },
415	    async ({ question, context }) => handleAsk('codex', question, context, deps),
416	  );
417	
418	  server.registerTool(
419	    'ask_claude',
420	    {
421	      description: "Ask the Claude agent a question, running it headless in the caller's cwd.",
422	      inputSchema: {
423	        question: z.string(),
424	        context: z.string().optional(),
425	      },
426	    },
427	    async ({ question, context }) => handleAsk('claude', question, context, deps),
428	  );
429	
430	  server.registerTool(
431	    'wait_for_status',
432	    {
433	      description:
434	        "Block until another agent's session reaches a status ('waiting' or 'idle'), or time out. Never throws — returns {status:'timeout'} as data on timeout, loop-guard trip, or approval denial.",
435	      inputSchema: {
436	        project: z.string(),
437	        session: z.string().optional(),
438	        status: z.enum(['waiting', 'idle']),
439	        timeoutSec: z.number().optional(),
440	      },
441	    },
442	    async ({ project, session, status, timeoutSec }) => handleWait(project, status, session, timeoutSec, deps),
443	  );
444	
445	  server.registerTool(
446	    'read_terminal',
447	    {
448	      description:
449	        "Read the last N lines of another agent's live terminal scrollback (ANSI-stripped). Refuses to read the caller's own session.",
450	      inputSchema: {
451	        project: z.string(),
452	        lines: z.number().optional(),
453	      },
454	    },
455	    async ({ project, lines }) => handleReadTerminal(project, lines, deps),
456	  );
457	
458	  return server;
459	}
460	
461	// Entry point for `seshmux mcp-bridge`: creates the server and connects it over stdio.
462	// deps is optional/overridable so tests can inject fakes without touching real stdio.
463	export async function startMcpBridge(deps: BridgeDeps = defaultBridgeDeps()): Promise<McpServer> {
464	  const server = createMcpBridgeServer(deps);
465	  await server.connect(new StdioServerTransport());
466	  return server;
467	}
